$s=db()->query("SELECT (SELECT COALESCE(SUM(amount),0) FROM donations WHERE status='verified') total,(SELECT COUNT(*) FROM donations WHERE status='pending') pending,(SELECT COUNT(*) FROM campaigns WHERE status='active') campaigns,(SELECT COUNT(*) FROM users WHERE role='donor') users")->fetch();
